using System.Collections;
using System.Collections.Generic;
using UnityEngine;

// ─── Acções NPC — Bloqueio Temporário de Formas ────────────────────────────
//
// Usadas quando uma área "retira" temporariamente animais ao player (ex: uma
// zona onde animais foram selados ou confiscados). As formas bloqueadas
// continuam visíveis (cinzentas) na roda de formas, mas não podem ser equipadas.
//
// Fluxo típico de "área com animais selados":
//   1. Action_LockForms         — bloqueia os animais da lista ao entrar na área.
//   2. [player joga a área sem esses animais]
//   3. Action_UnlockForms       — desbloqueia formas específicas (ou)
//      Action_ClearFormLocks    — remove TODOS os bloqueios de uma vez.
//
// Para bloquear (e opcionalmente restaurar) o estado completo do player
// (seeds, corações, inventário...) em conjunto com estes bloqueios, usar
// Action_SavePlayerSnapshot / Action_RestorePlayerSnapshot (Task #5).
//
// Nota: se o player estiver actualmente numa forma que vai ser bloqueada, o
// bloqueio NÃO o expulsa dela — o designer deve forçar uma troca de forma
// primeiro (ex: via Action_FreeAnimal → Action_ForceForm, se existir).

/// <summary>
/// Bloqueia temporariamente uma ou mais formas: ficam visíveis (cinzentas) na
/// roda de formas mas não podem ser equipadas. As formas já bloqueadas são
/// ignoradas (idempotente).
/// </summary>
[System.Serializable]
public class Action_LockForms : NpcAction
{
    [Tooltip("Formas a bloquear temporariamente. Ficam visíveis na roda mas não seleccionáveis (cinzentas).")]
    public List<AnimalFormData> forms = new List<AnimalFormData>();

    public override IEnumerator Execute(NpcController npc)
    {
        var switcher = FormLockUtil.GetSwitcher();
        if (switcher == null) yield break;

        foreach (var form in forms)
            switcher.LockForm(form);
    }
}

/// <summary>
/// Remove o bloqueio de uma ou mais formas específicas, tornando-as novamente
/// seleccionáveis (sem afectar outros bloqueios activos). As formas não
/// bloqueadas são ignoradas (idempotente).
/// </summary>
[System.Serializable]
public class Action_UnlockForms : NpcAction
{
    [Tooltip("Formas a desbloquear. Remove apenas o bloqueio temporário; a forma precisa de continuar na lista 'unlockedForms' do FormSwitcher para ser usável.")]
    public List<AnimalFormData> forms = new List<AnimalFormData>();

    public override IEnumerator Execute(NpcController npc)
    {
        var switcher = FormLockUtil.GetSwitcher();
        if (switcher == null) yield break;

        foreach (var form in forms)
            switcher.UnlockFormLock(form);
    }
}

/// <summary>
/// Remove TODOS os bloqueios temporários de formas de uma vez, restaurando
/// todas as formas desbloqueadas como seleccionáveis. Útil no final de uma
/// área de evento para garantir que nenhum bloqueio ficou activo.
/// </summary>
[System.Serializable]
public class Action_ClearFormLocks : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        FormLockUtil.GetSwitcher()?.ClearAllFormLocks();
        yield break;
    }
}

/// <summary>
/// Bloqueia TODAS as formas desbloqueadas excepto a forma inicial
/// (startingForm). Equivale a "o player perde todos os animais
/// temporariamente" sem removê-los da lista — o player continua a ver os
/// animais cinzentos na roda de formas como recordação do que tinha.
///
/// Nota: a forma actual do player NÃO é alterada por esta acção. Se quiser
/// que o player seja forçado para a forma inicial, use outra acção antes.
/// </summary>
[System.Serializable]
public class Action_LockAllFormsExceptStart : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        var switcher = FormLockUtil.GetSwitcher();
        if (switcher == null) yield break;

        foreach (var form in switcher.unlockedForms)
        {
            if (form == null || form == switcher.startingForm) continue;
            switcher.LockForm(form);
        }
    }
}

// ─── Utilitário interno ────────────────────────────────────────────────────

internal static class FormLockUtil
{
    internal static FormSwitcher GetSwitcher()
    {
        var playerT = PlayerLocator.Find();
        if (playerT == null)
        {
            Debug.LogWarning("[FormLockActions] Player não encontrado na cena.");
            return null;
        }

        var switcher = playerT.GetComponent<FormSwitcher>()
                    ?? playerT.GetComponentInChildren<FormSwitcher>();

        if (switcher == null)
            Debug.LogWarning("[FormLockActions] FormSwitcher não encontrado no Player.");

        return switcher;
    }
}
